const raw = items[0] ?? {};
const state = $getWorkflowStaticData('global');
const data = raw.json?.response ?? raw.json ?? {};
const error = raw.error ?? raw.json?.error ?? data?.error;
const failureThreshold = 2;
const checkUrl = '__OPS_INTERNAL_BASE_URL__/jobs/ops-check';

function errorDetail() {
  if (typeof error === 'string' && error) return error;
  if (error?.message) return error.message;
  if (raw.json?.message) return raw.json.message;
  if (data?.message) return data.message;
  return 'unexpected response';
}

function classifyTransport(detail) {
  const text = String(detail ?? '');
  if (/EAI_AGAIN|EAIAGAIN|ENOTFOUND|getaddrinfo/i.test(text)) return 'DNS lookup failed';
  if (/ECONNREFUSED|ECONNRESET|fetch failed/i.test(text)) return 'Internal ingress unreachable';
  if (/timed out|timeout/i.test(text)) return 'Ops check request timed out';
  return 'Ops check request failed';
}

function escapeTelegramText(value) {
  return String(value ?? '-').replace(/_/g, '\\_');
}

function formatKst(value) {
  const date = value ? new Date(value) : new Date();
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Asia/Seoul',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  });
  const parts = Object.fromEntries(formatter.formatToParts(date).map((part) => [part.type, part.value]));
  return `${parts.year}. ${parts.month}. ${parts.day}. ${parts.hour}:${parts.minute} KST`;
}

function transportFailureMessage(detail, streak) {
  return [
    '운영 상태 확인 경로 이상',
    `시각: ${formatKst()}`,
    `경로: ${checkUrl}`,
    `연속실패: ${streak}회`,
    `요약: ${classifyTransport(detail)}`,
    detail,
  ].join('\n');
}

function transportRecoveryMessage() {
  return [
    '운영 상태 확인 경로 복구',
    `시각: ${formatKst()}`,
    `경로: ${checkUrl}`,
    '요약: 내부 점검 경로 응답이 다시 정상화되었습니다.',
  ].join('\n');
}

function statusChangeMessage(check) {
  const issues = Array.isArray(check.issues) ? check.issues.slice(0, 5) : [];
  const generatedAt = formatKst(check.generated_at);
  const lines = [];

  if (check.overall_status === 'healthy') {
    lines.push('운영 상태 복구');
    lines.push(`시각: ${generatedAt}`);
    lines.push(`이전상태: ${escapeTelegramText(check.previous_overall_status ?? '-')}`);
    lines.push('현재상태: healthy');
    lines.push('요약: 모든 추적 대상이 정상 상태로 돌아왔습니다.');
    return lines.join('\n');
  }

  const statusLabel = check.overall_status === 'critical' ? 'CRITICAL' : 'WARNING';
  lines.push('운영 이상 감지');
  lines.push(`시각: ${generatedAt}`);
  lines.push(`상태: ${statusLabel}`);
  lines.push(`이전상태: ${escapeTelegramText(check.previous_overall_status ?? '-')}`);
  lines.push(`요약: ${escapeTelegramText(check.summary ?? '-')}`);
  for (const issue of issues) {
    const sourceType = escapeTelegramText(issue.source_type ?? 'unknown');
    const sourceName = escapeTelegramText(issue.source_name ?? 'unknown');
    const message = escapeTelegramText(issue.message ?? '-');
    lines.push(`- [${sourceType}] ${sourceName}: ${message}`);
  }
  return lines.join('\n');
}

if (error || typeof data?.changed === 'undefined' || typeof data?.overall_status === 'undefined') {
  const detail = errorDetail();
  const streak = Number(state.transportFailureStreak ?? 0) + 1;
  state.transportFailureStreak = streak;
  if (streak < failureThreshold) {
    return [];
  }
  if (state.transportFailureAlerted === true) {
    return [];
  }
  state.transportFailureAlerted = true;
  return [{ json: { message: transportFailureMessage(detail, streak) } }];
}

const outputs = [];
if (state.transportFailureAlerted === true) {
  outputs.push({ json: { message: transportRecoveryMessage() } });
}
state.transportFailureStreak = 0;
state.transportFailureAlerted = false;

if (data.changed === true) {
  outputs.push({ json: { message: statusChangeMessage(data) } });
}

return outputs;
